        if re.fullmatch(r"[-+]?(?:\d+\.\d*|\.\d+|\d+)(?:[eE][-+]?\d+)?", token):
            return float(token)
        # Also allow pure exponent like 1e5 without decimal point
        if re.fullmatch(r"[-+]?\d+(?:[eE][-+]?\d+)", token):
            return float(token)
